import { useState, useEffect } from "react";
import { useSelector } from "react-redux";
import { useParams, useNavigate } from "react-router-dom";
import { toast } from "react-toastify";

function EditCourse() {
  const user = useSelector((state) => state.auth.user);
  const { id } = useParams();
  const navigate = useNavigate();
  const [course, setCourse] = useState(null);
  const [name, setName] = useState("");
  const [description, setDescription] = useState("");
  const [classId, setClassId] = useState("");
  const [classes, setClasses] = useState([]);
  const [file, setFile] = useState(null);

  useEffect(() => {
    if (user?.role === "teacher") {
      fetch(`http://localhost:3001/courses/${id}`)
        .then((res) => res.json())
        .then((data) => {
          setCourse(data);
          setName(data.name);
          setDescription(data.description || "");
          setClassId(data.classId || "");
        })
        .catch((error) => {
          toast.error("Ошибка загрузки курса");
          navigate("/courses");
        });
      fetch("http://localhost:3001/classes")
        .then((res) => res.json())
        .then((data) => setClasses(Array.isArray(data) ? data : []))
        .catch((error) => toast.error("Ошибка загрузки классов"));
    }
  }, [user, id, navigate]);

  async function handleSubmit(e) {
    e.preventDefault();
    try {
      const updatedCourse = {
        name,
        description,
        classId: parseInt(classId),
        teacherId: user.id,
      };
      const response = await fetch(`http://localhost:3001/courses/${id}`, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(updatedCourse),
      });
      if (response.ok) {
        toast.success("Курс обновлен!");
        navigate("/courses");
      } else {
        toast.error("Не удалось обновить курс");
      }
    } catch (error) {
      console.error("Course update error:", error);
      toast.error("Сетевая ошибка при обновлении курса");
    }
  }

  async function handleFileUpload(e) {
    e.preventDefault();
    if (!file) {
      toast.error("Выберите файл!");
      return;
    }
    const formData = new FormData();
    formData.append("file", file);
    try {
      const response = await fetch("http://localhost:3002/upload", {
        method: "POST",
        body: formData,
      });
      if (response.ok) {
        const { filename, originalName } = await response.json();
        const fileData = {
          courseId: parseInt(id),
          filename,
          originalName,
          path: `uploads/${filename}`,
          createdAt: new Date().toISOString(),
        };
        const fileResponse = await fetch("http://localhost:3001/files", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(fileData),
        });
        if (fileResponse.ok) {
          toast.success("Файл загружен!");
          setFile(null);
          await fetch("http://localhost:3001/notifications", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
              userId: user.id,
              message: `Файл "${originalName}" загружен для курса "${name}".`,
              createdAt: new Date().toISOString(),
            }),
          });
        } else {
          toast.error("Не удалось сохранить данные файла");
        }
      } else {
        const errorData = await response.json();
        toast.error(`Не удалось загрузить файл: ${errorData.error || "Ошибка сервера"}`);
      }
    } catch (error) {
      console.error("File upload error:", error);
      toast.error("Сетевая ошибка при загрузке файла");
    }
  }

  if (user?.role !== "teacher") {
    return <div className="container mt-5"><h1>Доступ запрещен</h1></div>;
  }

  if (!course) {
    return <div className="container mt-5"><h1>Загрузка...</h1></div>;
  }

  return (
    <div className="container mt-5">
      <h1 className="text-center mb-4">Редактировать курс</h1>
      <div className="card shadow">
        <div className="card-body">
          <form onSubmit={handleSubmit}>
            <div className="mb-3">
              <label htmlFor="name" className="form-label">Название курса</label>
              <input
                type="text"
                id="name"
                className="form-control"
                value={name}
                onChange={(e) => setName(e.target.value)}
                required
              />
            </div>
            <div className="mb-3">
              <label htmlFor="description" className="form-label">Описание</label>
              <textarea
                id="description"
                className="form-control"
                value={description}
                onChange={(e) => setDescription(e.target.value)}
              />
            </div>
            <div className="mb-3">
              <label htmlFor="class" className="form-label">Класс</label>
              <select
                id="class"
                className="form-select"
                value={classId}
                onChange={(e) => setClassId(e.target.value)}
                required
              >
                <option value="">-- Выберите класс --</option>
                {classes.map((cls) => (
                  <option key={cls.id} value={cls.id}>
                    {cls.name}
                  </option>
                ))}
              </select>
            </div>
            <button type="submit" className="btn btn-primary w-100">Сохранить изменения</button>
          </form>
          <hr />
          <h3>Загрузить файл</h3>
          <form onSubmit={handleFileUpload}>
            <div className="mb-3">
              <label htmlFor="file" className="form-label">Выберите файл</label>
              <input
                type="file"
                id="file"
                className="form-control"
                onChange={(e) => setFile(e.target.files[0])}
              />
            </div>
            <button type="submit" className="btn btn-primary w-100">Загрузить</button>
          </form>
        </div>
      </div>
    </div>
  );
}

export default EditCourse;
